 1→import { create } from "zustand";
 2→import { persist } from "zustand/middleware";
 3→
 4→interface SidebarState {
 5→  // Sidebar-specific state
 6→  collapsedRepos: Set<string>;
 7→  toggleRepoCollapse: (repoId: string) => void;
 8→  expandRepo: (repoId: string) => void;
 9→
10→  // Repos where user expanded the "Show more" stale workspaces
11→  expandedOldWorkspaces: Set<string>;
12→  toggleOldWorkspaces: (repoId: string) => void;
13→
14→  // Repository ordering
15→  repositoryOrder: string[];
16→  setRepositoryOrder: (order: string[]) => void;
17→  reorderRepositories: <T extends { repo_id: string }>(repos: T[]) => T[];
18→}
19→
20→export const useSidebarStore = create<SidebarState>()(
21→  persist(
22→    (set, get) => ({
23→      // Existing state
24→      collapsedRepos: new Set(),
25→      toggleRepoCollapse: (repoId) =>
26→        set((state) => {
27→          const newCollapsed = new Set(state.collapsedRepos);
28→          if (newCollapsed.has(repoId)) {
29→            newCollapsed.delete(repoId);
30→          } else {
31→            newCollapsed.add(repoId);
32→          }
33→          return { collapsedRepos: newCollapsed };
34→        }),
35→      expandRepo: (repoId) =>
36→        set((state) => {
37→          if (!state.collapsedRepos.has(repoId)) return state;
38→          const newCollapsed = new Set(state.collapsedRepos);
39→          newCollapsed.delete(repoId);
40→          return { collapsedRepos: newCollapsed };
41→        }),
42→
43→      // Stale workspace expansion (per-repo)
44→      expandedOldWorkspaces: new Set(),
45→      toggleOldWorkspaces: (repoId) =>
46→        set((state) => {
47→          const next = new Set(state.expandedOldWorkspaces);
48→          if (next.has(repoId)) {
49→            next.delete(repoId);
50→          } else {
51→            next.add(repoId);
52→          }
53→          return { expandedOldWorkspaces: next };
54→        }),
55→
56→      // Repository ordering
57→      repositoryOrder: [],
58→
59→      setRepositoryOrder: (order) => set({ repositoryOrder: order }),
60→
61→      /**
62→       * Reorder repositories based on user preferences
63→       * Unordered repos appear at the end in their original order
64→       */
65→      reorderRepositories: (repos) => {
66→        const { repositoryOrder } = get();
67→
68→        // If no custom order, return as-is
69→        if (repositoryOrder.length === 0) return repos;
70→
71→        // Create lookup map for O(1) access
72→        const orderMap = new Map(repositoryOrder.map((id, idx) => [id, idx]));
73→
74→        return [...repos].sort((a, b) => {
75→          const indexA = orderMap.get(a.repo_id) ?? Infinity;
76→          const indexB = orderMap.get(b.repo_id) ?? Infinity;
77→          return indexA - indexB;
78→        });
79→      },
80→    }),
81→    {
82→      name: "sidebar-storage",
83→      // Serialize Set properly for localStorage
84→      partialize: (state) => ({
85→        collapsedRepos: Array.from(state.collapsedRepos),
86→        expandedOldWorkspaces: Array.from(state.expandedOldWorkspaces),
87→        repositoryOrder: state.repositoryOrder,
88→      }),
89→      merge: (persistedState: any, currentState) => ({
90→        ...currentState,
91→        collapsedRepos: new Set(persistedState?.collapsedRepos || []),
92→        expandedOldWorkspaces: new Set(persistedState?.expandedOldWorkspaces || []),
93→        repositoryOrder: persistedState?.repositoryOrder || [],
94→      }),
95→    }
96→  )
